"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  TrendingUp,
  TrendingDown,
  Search,
  Filter,
  Download,
  Calendar,
  ChevronLeft,
  ChevronRight,
  X,
  Clock,
  DollarSign,
  BarChart3,
  Target,
  ArrowUpRight,
  ArrowDownRight,
} from "lucide-react";
import { fetchTradeHistory } from "@/lib/services/mock-api";

type TradeType = "buy" | "sell";

interface Trade {
  id: string;
  symbol: string;
  type: TradeType;
  openPrice: number;
  closePrice: number;
  volume: number;
  profitLoss: number;
  openTime: string;
  closeTime: string;
  duration: string;
  pips: number;
  challengeId: string;
  challengeName: string;
}

// Convert API trade to UI trade format
function mapApiTrade(apiTrade: {
  id: string;
  symbol: string;
  type: "buy" | "sell";
  lot_size: number;
  entry_price: number;
  exit_price?: number;
  profit_loss?: number;
  opened_at: string;
  closed_at?: string;
}): Trade {
  const openTime = new Date(apiTrade.opened_at);
  const closeTime = apiTrade.closed_at ? new Date(apiTrade.closed_at) : openTime;
  const duration = Math.floor((closeTime.getTime() - openTime.getTime()) / 60000);
  const hours = Math.floor(duration / 60);
  const mins = duration % 60;

  return {
    id: apiTrade.id,
    symbol: apiTrade.symbol,
    type: apiTrade.type,
    openPrice: apiTrade.entry_price,
    closePrice: apiTrade.exit_price || apiTrade.entry_price,
    volume: apiTrade.lot_size,
    profitLoss: apiTrade.profit_loss || 0,
    openTime: apiTrade.opened_at,
    closeTime: apiTrade.closed_at || apiTrade.opened_at,
    duration: `${hours}h ${mins}m`,
    pips: Math.round((apiTrade.profit_loss || 0) / (apiTrade.lot_size * 10)),
    challengeId: "ch-001",
    challengeName: "$25K Challenge",
  };
}

const challenges = [
  { id: "all", name: "All Challenges" },
  { id: "ch-001", name: "$25K Challenge" },
  { id: "ch-002", name: "$50K Funded" },
];

const symbols = [
  "All Symbols",
  "EUR/USD",
  "GBP/USD",
  "USD/JPY",
  "XAU/USD",
  "NAS100",
  "US30",
  "EUR/GBP",
  "GBP/JPY",
  "AUD/USD",
  "USD/CAD",
];

const ITEMS_PER_PAGE = 8;

export default function TradesPage() {
  const [trades, setTrades] = useState<Trade[]>([]);
  const [_loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedChallenge, setSelectedChallenge] = useState("all");
  const [selectedSymbol, setSelectedSymbol] = useState("All Symbols");
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [currentPage, setCurrentPage] = useState(1);
  const [selectedTrade, setSelectedTrade] = useState<Trade | null>(null);

  // Load trades from API
  useEffect(() => {
    const loadTrades = async () => {
      setLoading(true);
      try {
        const response = await fetchTradeHistory({ limit: 100 });
        if (response.data) {
          setTrades(response.data.map(mapApiTrade));
        }
      } catch (error) {
        console.error("Failed to load trades:", error);
      } finally {
        setLoading(false);
      }
    };
    loadTrades();
  }, []);

  // Filter trades
  const filteredTrades = trades.filter((trade: Trade) => {
    const matchesSearch =
      trade.symbol.toLowerCase().includes(searchQuery.toLowerCase()) ||
      trade.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesChallenge =
      selectedChallenge === "all" || trade.challengeId === selectedChallenge;
    const matchesSymbol =
      selectedSymbol === "All Symbols" || trade.symbol === selectedSymbol;
    const tradeDate = new Date(trade.closeTime);
    const matchesDateFrom = !dateFrom || tradeDate >= new Date(dateFrom);
    const matchesDateTo = !dateTo || tradeDate <= new Date(dateTo + "T23:59:59");
    return (
      matchesSearch &&
      matchesChallenge &&
      matchesSymbol &&
      matchesDateFrom &&
      matchesDateTo
    );
  });

  // Pagination
  const totalPages = Math.ceil(filteredTrades.length / ITEMS_PER_PAGE);
  const paginatedTrades = filteredTrades.slice(
    (currentPage - 1) * ITEMS_PER_PAGE,
    currentPage * ITEMS_PER_PAGE
  );

  // Stats
  const totalTrades = filteredTrades.length;
  const winningTrades = filteredTrades.filter((t: Trade) => t.profitLoss > 0).length;
  const totalProfit = filteredTrades.reduce((sum: number, t: Trade) => sum + t.profitLoss, 0);
  const winRate = totalTrades > 0 ? (winningTrades / totalTrades) * 100 : 0;
  const averageTrade =
    totalTrades > 0 ? totalProfit / totalTrades : 0;

  // Export to CSV
  const exportToCSV = () => {
    const headers = [
      "ID",
      "Symbol",
      "Type",
      "Volume",
      "Open Price",
      "Close Price",
      "P/L",
      "Pips",
      "Open Time",
      "Close Time",
      "Duration",
      "Challenge",
    ];
    const rows = filteredTrades.map((t: Trade) => [
      t.id,
      t.symbol,
      t.type,
      t.volume,
      t.openPrice,
      t.closePrice,
      t.profitLoss,
      t.pips,
      t.openTime,
      t.closeTime,
      t.duration,
      t.challengeName,
    ]);

    const csvContent = [headers.join(","), ...rows.map((r: (string | number)[]) => r.join(","))].join(
      "\n"
    );
    const blob = new Blob([csvContent], { type: "text/csv" });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `trades_${new Date().toISOString().split("T")[0]}.csv`;
    a.click();
    window.URL.revokeObjectURL(url);
  };

  const clearFilters = () => {
    setSearchQuery("");
    setSelectedChallenge("all");
    setSelectedSymbol("All Symbols");
    setDateFrom("");
    setDateTo("");
    setCurrentPage(1);
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl lg:text-3xl font-bold">Trade History</h1>
          <p className="text-foreground/60">
            Review all your trading activity across challenges
          </p>
        </div>
        <button
          onClick={exportToCSV}
          className="inline-flex items-center gap-2 px-4 py-2 border border-border rounded-lg hover:bg-foreground/5 transition-colors"
        >
          <Download className="w-5 h-5" />
          Export CSV
        </button>
      </div>

      {/* Stats Overview */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="p-4 bg-foreground/[0.02] border border-border rounded-xl"
        >
          <div className="flex items-center gap-3 mb-2">
            <div className="w-8 h-8 rounded-lg bg-blue-400/10 flex items-center justify-center">
              <BarChart3 className="w-4 h-4 text-blue-400" />
            </div>
          </div>
          <p className="text-sm text-foreground/60 mb-1">Total Trades</p>
          <p className="text-2xl font-bold">{totalTrades}</p>
        </motion.div>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
          className="p-4 bg-foreground/[0.02] border border-border rounded-xl"
        >
          <div className="flex items-center gap-3 mb-2">
            <div className="w-8 h-8 rounded-lg bg-green-400/10 flex items-center justify-center">
              <Target className="w-4 h-4 text-green-400" />
            </div>
          </div>
          <p className="text-sm text-foreground/60 mb-1">Win Rate</p>
          <p className="text-2xl font-bold text-green-400">
            {winRate.toFixed(1)}%
          </p>
        </motion.div>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
          className="p-4 bg-foreground/[0.02] border border-border rounded-xl"
        >
          <div className="flex items-center gap-3 mb-2">
            <div
              className={`w-8 h-8 rounded-lg ${totalProfit >= 0 ? "bg-green-400/10" : "bg-red-400/10"} flex items-center justify-center`}
            >
              <DollarSign
                className={`w-4 h-4 ${totalProfit >= 0 ? "text-green-400" : "text-red-400"}`}
              />
            </div>
          </div>
          <p className="text-sm text-foreground/60 mb-1">Total P/L</p>
          <p
            className={`text-2xl font-bold ${totalProfit >= 0 ? "text-green-400" : "text-red-400"}`}
          >
            {totalProfit >= 0 ? "+" : ""}${totalProfit.toLocaleString()}
          </p>
        </motion.div>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.3 }}
          className="p-4 bg-foreground/[0.02] border border-border rounded-xl"
        >
          <div className="flex items-center gap-3 mb-2">
            <div
              className={`w-8 h-8 rounded-lg ${averageTrade >= 0 ? "bg-green-400/10" : "bg-red-400/10"} flex items-center justify-center`}
            >
              {averageTrade >= 0 ? (
                <TrendingUp
                  className={`w-4 h-4 ${averageTrade >= 0 ? "text-green-400" : "text-red-400"}`}
                />
              ) : (
                <TrendingDown className="w-4 h-4 text-red-400" />
              )}
            </div>
          </div>
          <p className="text-sm text-foreground/60 mb-1">Avg Trade</p>
          <p
            className={`text-2xl font-bold ${averageTrade >= 0 ? "text-green-400" : "text-red-400"}`}
          >
            {averageTrade >= 0 ? "+" : ""}${averageTrade.toFixed(2)}
          </p>
        </motion.div>
      </div>

      {/* Filters */}
      <div className="bg-foreground/[0.02] border border-border rounded-xl p-4">
        <div className="flex flex-wrap gap-4">
          {/* Search */}
          <div className="relative flex-1 min-w-[200px]">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-foreground/40" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => {
                setSearchQuery(e.target.value);
                setCurrentPage(1);
              }}
              placeholder="Search by symbol or ID..."
              className="w-full pl-10 pr-4 py-2.5 bg-background border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all"
            />
          </div>

          {/* Challenge Filter */}
          <div className="relative">
            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-foreground/40" />
            <select
              value={selectedChallenge}
              onChange={(e) => {
                setSelectedChallenge(e.target.value);
                setCurrentPage(1);
              }}
              className="pl-10 pr-8 py-2.5 bg-background border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all appearance-none cursor-pointer min-w-[160px]"
            >
              {challenges.map((c) => (
                <option key={c.id} value={c.id}>
                  {c.name}
                </option>
              ))}
            </select>
          </div>

          {/* Symbol Filter */}
          <select
            value={selectedSymbol}
            onChange={(e) => {
              setSelectedSymbol(e.target.value);
              setCurrentPage(1);
            }}
            className="px-4 py-2.5 bg-background border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all appearance-none cursor-pointer min-w-[140px]"
          >
            {symbols.map((s) => (
              <option key={s} value={s}>
                {s}
              </option>
            ))}
          </select>

          {/* Date From */}
          <div className="relative">
            <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-foreground/40" />
            <input
              type="date"
              value={dateFrom}
              onChange={(e) => {
                setDateFrom(e.target.value);
                setCurrentPage(1);
              }}
              className="pl-10 pr-4 py-2.5 bg-background border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all"
            />
          </div>

          {/* Date To */}
          <div className="relative">
            <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-foreground/40" />
            <input
              type="date"
              value={dateTo}
              onChange={(e) => {
                setDateTo(e.target.value);
                setCurrentPage(1);
              }}
              className="pl-10 pr-4 py-2.5 bg-background border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all"
            />
          </div>

          {/* Clear Filters */}
          {(searchQuery ||
            selectedChallenge !== "all" ||
            selectedSymbol !== "All Symbols" ||
            dateFrom ||
            dateTo) && (
              <button
                onClick={clearFilters}
                className="px-4 py-2.5 text-foreground/60 hover:text-foreground transition-colors flex items-center gap-2"
              >
                <X className="w-4 h-4" />
                Clear
              </button>
            )}
        </div>
      </div>

      {/* Trades Table */}
      <div className="bg-foreground/[0.02] border border-border rounded-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="text-left text-sm text-foreground/60 border-b border-border bg-foreground/[0.02]">
                <th className="px-6 py-4 font-medium">Symbol</th>
                <th className="px-6 py-4 font-medium">Type</th>
                <th className="px-6 py-4 font-medium">Volume</th>
                <th className="px-6 py-4 font-medium">Entry / Exit</th>
                <th className="px-6 py-4 font-medium">P/L</th>
                <th className="px-6 py-4 font-medium">Pips</th>
                <th className="px-6 py-4 font-medium">Time</th>
                <th className="px-6 py-4 font-medium">Challenge</th>
              </tr>
            </thead>
            <tbody>
              {paginatedTrades.length === 0 ? (
                <tr>
                  <td colSpan={8} className="px-6 py-12 text-center">
                    <div className="w-16 h-16 bg-foreground/5 rounded-full flex items-center justify-center mx-auto mb-4">
                      <BarChart3 className="w-8 h-8 text-foreground/30" />
                    </div>
                    <p className="text-foreground/60">No trades found</p>
                    <p className="text-sm text-foreground/40 mt-1">
                      Try adjusting your filters
                    </p>
                  </td>
                </tr>
              ) : (
                paginatedTrades.map((trade) => (
                  <motion.tr
                    key={trade.id}
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    className="border-b border-border/50 last:border-0 hover:bg-foreground/[0.02] cursor-pointer"
                    onClick={() => setSelectedTrade(trade)}
                  >
                    <td className="px-6 py-4">
                      <span className="font-semibold">{trade.symbol}</span>
                    </td>
                    <td className="px-6 py-4">
                      <span
                        className={`inline-flex items-center gap-1 px-2 py-1 text-xs font-medium rounded-full ${trade.type === "buy"
                          ? "bg-green-400/20 text-green-400"
                          : "bg-red-400/20 text-red-400"
                          }`}
                      >
                        {trade.type === "buy" ? (
                          <ArrowUpRight className="w-3 h-3" />
                        ) : (
                          <ArrowDownRight className="w-3 h-3" />
                        )}
                        {trade.type.toUpperCase()}
                      </span>
                    </td>
                    <td className="px-6 py-4">{trade.volume}</td>
                    <td className="px-6 py-4">
                      <div className="text-sm">
                        <p>{trade.openPrice}</p>
                        <p className="text-foreground/60">{trade.closePrice}</p>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span
                        className={`font-semibold ${trade.profitLoss >= 0 ? "text-green-400" : "text-red-400"}`}
                      >
                        {trade.profitLoss >= 0 ? "+" : ""}$
                        {trade.profitLoss.toLocaleString()}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <span
                        className={
                          trade.pips >= 0 ? "text-green-400" : "text-red-400"
                        }
                      >
                        {trade.pips >= 0 ? "+" : ""}
                        {trade.pips}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm">
                        <p>
                          {new Date(trade.closeTime).toLocaleDateString()}
                        </p>
                        <p className="text-foreground/60">{trade.duration}</p>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-sm text-foreground/70">
                      {trade.challengeName}
                    </td>
                  </motion.tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination */}
        {totalPages > 1 && (
          <div className="flex items-center justify-between px-6 py-4 border-t border-border">
            <p className="text-sm text-foreground/60">
              Showing {(currentPage - 1) * ITEMS_PER_PAGE + 1} to{" "}
              {Math.min(currentPage * ITEMS_PER_PAGE, filteredTrades.length)} of{" "}
              {filteredTrades.length} trades
            </p>
            <div className="flex items-center gap-2">
              <button
                onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                disabled={currentPage === 1}
                className="p-2 rounded-lg border border-border hover:bg-foreground/5 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                <ChevronLeft className="w-5 h-5" />
              </button>
              {Array.from({ length: totalPages }, (_, i) => i + 1).map((page) => (
                <button
                  key={page}
                  onClick={() => setCurrentPage(page)}
                  className={`w-10 h-10 rounded-lg font-medium transition-colors ${currentPage === page
                    ? "bg-primary text-primary-foreground"
                    : "hover:bg-foreground/5"
                    }`}
                >
                  {page}
                </button>
              ))}
              <button
                onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
                disabled={currentPage === totalPages}
                className="p-2 rounded-lg border border-border hover:bg-foreground/5 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                <ChevronRight className="w-5 h-5" />
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Trade Detail Modal */}
      <AnimatePresence>
        {selectedTrade && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-background/80 backdrop-blur-sm"
            onClick={() => setSelectedTrade(null)}
          >
            <motion.div
              initial={{ opacity: 0, scale: 0.95, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95, y: 20 }}
              className="w-full max-w-lg bg-background border border-border rounded-2xl shadow-xl"
              onClick={(e) => e.stopPropagation()}
            >
              {/* Modal Header */}
              <div className="flex items-center justify-between p-6 border-b border-border">
                <div>
                  <h2 className="text-xl font-bold">{selectedTrade.symbol}</h2>
                  <p className="text-sm text-foreground/60">
                    Trade ID: {selectedTrade.id}
                  </p>
                </div>
                <button
                  onClick={() => setSelectedTrade(null)}
                  className="w-8 h-8 rounded-lg hover:bg-foreground/10 flex items-center justify-center transition-colors"
                >
                  <X className="w-5 h-5" />
                </button>
              </div>

              {/* Modal Body */}
              <div className="p-6 space-y-4">
                {/* Type and P/L */}
                <div className="flex items-center justify-between">
                  <span
                    className={`inline-flex items-center gap-1 px-3 py-1.5 text-sm font-medium rounded-full ${selectedTrade.type === "buy"
                      ? "bg-green-400/20 text-green-400"
                      : "bg-red-400/20 text-red-400"
                      }`}
                  >
                    {selectedTrade.type === "buy" ? (
                      <ArrowUpRight className="w-4 h-4" />
                    ) : (
                      <ArrowDownRight className="w-4 h-4" />
                    )}
                    {selectedTrade.type.toUpperCase()}
                  </span>
                  <span
                    className={`text-2xl font-bold ${selectedTrade.profitLoss >= 0 ? "text-green-400" : "text-red-400"}`}
                  >
                    {selectedTrade.profitLoss >= 0 ? "+" : ""}$
                    {selectedTrade.profitLoss.toLocaleString()}
                  </span>
                </div>

                {/* Details Grid */}
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-foreground/[0.02] rounded-lg p-4">
                    <p className="text-sm text-foreground/60 mb-1">Volume</p>
                    <p className="font-semibold">{selectedTrade.volume} lots</p>
                  </div>
                  <div className="bg-foreground/[0.02] rounded-lg p-4">
                    <p className="text-sm text-foreground/60 mb-1">Pips</p>
                    <p
                      className={`font-semibold ${selectedTrade.pips >= 0 ? "text-green-400" : "text-red-400"}`}
                    >
                      {selectedTrade.pips >= 0 ? "+" : ""}
                      {selectedTrade.pips}
                    </p>
                  </div>
                  <div className="bg-foreground/[0.02] rounded-lg p-4">
                    <p className="text-sm text-foreground/60 mb-1">Entry Price</p>
                    <p className="font-semibold">{selectedTrade.openPrice}</p>
                  </div>
                  <div className="bg-foreground/[0.02] rounded-lg p-4">
                    <p className="text-sm text-foreground/60 mb-1">Exit Price</p>
                    <p className="font-semibold">{selectedTrade.closePrice}</p>
                  </div>
                </div>

                {/* Time Info */}
                <div className="bg-foreground/[0.02] rounded-lg p-4">
                  <div className="flex items-center gap-2 mb-3">
                    <Clock className="w-5 h-5 text-foreground/60" />
                    <span className="font-medium">Trade Duration</span>
                  </div>
                  <div className="grid grid-cols-2 gap-4 text-sm">
                    <div>
                      <p className="text-foreground/60 mb-1">Opened</p>
                      <p className="font-medium">
                        {new Date(selectedTrade.openTime).toLocaleString()}
                      </p>
                    </div>
                    <div>
                      <p className="text-foreground/60 mb-1">Closed</p>
                      <p className="font-medium">
                        {new Date(selectedTrade.closeTime).toLocaleString()}
                      </p>
                    </div>
                  </div>
                  <div className="mt-3 pt-3 border-t border-border">
                    <p className="text-foreground/60 text-sm">
                      Duration: <span className="font-medium text-foreground">{selectedTrade.duration}</span>
                    </p>
                  </div>
                </div>

                {/* Challenge */}
                <div className="flex items-center justify-between text-sm bg-foreground/[0.02] rounded-lg p-4">
                  <span className="text-foreground/60">Challenge</span>
                  <span className="font-medium">{selectedTrade.challengeName}</span>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

"use client";

import { useRef, useEffect, useState, useCallback } from "react";
import Link from "next/link";
import {
  motion,
  useScroll,
  useTransform,
  useMotionValue,
  useSpring,
  useMotionTemplate,
  AnimatePresence,
} from "framer-motion";
import { ArrowRight, ShieldCheck, Zap, Activity, TrendingUp, Users, DollarSign } from "lucide-react";

/**
 * 21st.dev Super Hero — Spawn Engine Build
 * DNA: Cinematic Split + Glass Surface + Magnetic Warp + Prestige Mood + Layered Composition
 * Chaos: Glow Pulse + Holographic Sheen + Dot Matrix Underlay
 * Preserved: DashboardCard (Chart)
 */

/* ─── ENGINE CONSTANTS ─── */
const fadeInUp = {
  initial: { opacity: 0, y: 24 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.6, ease: [0.25, 0.46, 0.45, 0.94] },
};

const hoverScale = {
  whileHover: { scale: 1.03, boxShadow: "0 0 30px rgba(199,162,87,0.25)" },
  whileTap: { scale: 0.97 },
  transition: { type: "spring", stiffness: 400, damping: 25 },
};

const EASE_CINEMATIC = [0.25, 0.46, 0.45, 0.94] as const;

const staggerContainer = {
  animate: { transition: { staggerChildren: 0.1, delayChildren: 0.2 } },
};

/* ─── DATA ─── */
const activityFeed = [
  { action: "Funded", amount: "$50K", user: "Alex K.", time: "2m ago" },
  { action: "Payout", amount: "$4,200", user: "Sam R.", time: "5m ago" },
  { action: "Passed", amount: "Phase 1", user: "Jordan T.", time: "8m ago" },
  { action: "Funded", amount: "$100K", user: "Taylor M.", time: "12m ago" },
  { action: "Payout", amount: "$8,500", user: "Morgan L.", time: "15m ago" },
];

const heroStats = [
  { icon: TrendingUp, value: "+127%", label: "Avg Return", color: "text-[#C7A257]" },
  { icon: Users, value: "2,847", label: "Funded Traders", color: "text-white" },
  { icon: DollarSign, value: "$2.4M", label: "Total Payouts", color: "text-[#C7A257]" },
];

/* ─── PROFIT CURVE SVG ─── */
const PROFIT_PATH =
  "M 0 80 C 20 75, 40 70, 60 55 S 100 60, 120 45 S 160 30, 180 35 S 220 20, 240 15 S 270 10, 280 8";
const PROFIT_PATH_LENGTH = 420;

/* ─── FLOATING PARTICLES ─── */
function FloatingParticles() {
  return (
    <div className="absolute inset-0 overflow-hidden pointer-events-none">
      {Array.from({ length: 20 }).map((_, i) => (
        <motion.div
          key={i}
          className="absolute w-1 h-1 rounded-full bg-[#C7A257]"
          style={{
            left: `${Math.random() * 100}%`,
            top: `${Math.random() * 100}%`,
            opacity: Math.random() * 0.3 + 0.05,
          }}
          animate={{
            y: [0, -30 - Math.random() * 40, 0],
            x: [0, (Math.random() - 0.5) * 20, 0],
            opacity: [0.05, 0.3, 0.05],
          }}
          transition={{
            duration: 4 + Math.random() * 6,
            repeat: Infinity,
            delay: Math.random() * 5,
            ease: "easeInOut",
          }}
        />
      ))}
    </div>
  );
}

/* ─── DASHBOARD CARD (Preserved + Enhanced) ─── */
function DashboardCard() {
  const [time, setTime] = useState("");
  const [isVisible, setIsVisible] = useState(false);

  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  const rotateX = useTransform(mouseY, [-0.5, 0.5], [8, -8]);
  const rotateY = useTransform(mouseX, [-0.5, 0.5], [-8, 8]);

  const handleMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width - 0.5;
    const y = (e.clientY - rect.top) / rect.height - 0.5;
    mouseX.set(x);
    mouseY.set(y);
  }, [mouseX, mouseY]);

  const handleMouseLeave = useCallback(() => {
    mouseX.set(0);
    mouseY.set(0);
  }, [mouseX, mouseY]);

  useEffect(() => {
    const update = () =>
      setTime(
        new Date().toLocaleTimeString("en-US", {
          hour12: false,
          hour: "2-digit",
          minute: "2-digit",
          second: "2-digit",
        })
      );
    update();
    const timer = setInterval(update, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const timeout = setTimeout(() => setIsVisible(true), 1200);
    return () => clearTimeout(timeout);
  }, []);

  return (
    <motion.div
      className="relative w-full holographic-sheen glow-pulse"
      style={{ rotateX, rotateY, transformPerspective: 1200 }}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      transition={{ type: "spring", stiffness: 400, damping: 30 }}
    >
      <div className="relative z-[2] border border-white/[0.08] bg-[#050505]/95 backdrop-blur-xl overflow-hidden">
        {/* Header */}
        <div className="flex items-center justify-between border-b border-white/[0.06] bg-black/60 px-4 py-3">
          <div className="flex items-center gap-2.5">
            <motion.div
              className="w-2 h-2 bg-[#C7A257] rounded-full"
              animate={{ scale: [1, 1.5, 1], opacity: [1, 0.5, 1] }}
              transition={{ duration: 1.5, repeat: Infinity, ease: "easeInOut" }}
            />
            <span className="text-[10px] sm:text-xs font-mono text-white/50 tracking-[0.2em] uppercase">
              Performance Pulse
            </span>
          </div>
          <span
            className="text-[10px] sm:text-xs font-mono text-[#C7A257]/80"
            suppressHydrationWarning
          >
            {time || "00:00:00"}
          </span>
        </div>

        {/* Chart Area */}
        <div className="p-4 sm:p-6">
          <div className="relative h-28 sm:h-36 mb-5">
            <svg
              viewBox="0 0 280 90"
              className="w-full h-full"
              preserveAspectRatio="none"
            >
              {[20, 40, 60, 80].map((y) => (
                <line
                  key={y}
                  x1="0"
                  x2="280"
                  y1={y}
                  y2={y}
                  stroke="rgba(255,255,255,0.03)"
                  strokeWidth="0.5"
                />
              ))}

              <defs>
                <linearGradient id="profitGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor="rgba(199, 162, 87, 0.2)" />
                  <stop offset="100%" stopColor="rgba(199, 162, 87, 0)" />
                </linearGradient>
                <linearGradient id="lineGradient" x1="0" y1="0" x2="1" y2="0">
                  <stop offset="0%" stopColor="#C7A257" stopOpacity="0.3" />
                  <stop offset="50%" stopColor="#C7A257" stopOpacity="1" />
                  <stop offset="100%" stopColor="#F0D78C" stopOpacity="1" />
                </linearGradient>
              </defs>

              <path
                d={`${PROFIT_PATH} L 280 90 L 0 90 Z`}
                fill="url(#profitGradient)"
                opacity={isVisible ? 1 : 0}
                style={{ transition: "opacity 1s ease-out 0.5s" }}
              />

              <path
                d={PROFIT_PATH}
                fill="none"
                stroke="url(#lineGradient)"
                strokeWidth="2"
                strokeLinecap="round"
                style={{
                  strokeDasharray: PROFIT_PATH_LENGTH,
                  strokeDashoffset: isVisible ? 0 : PROFIT_PATH_LENGTH,
                  transition: "stroke-dashoffset 2.5s ease-out",
                }}
              />

              {isVisible && (
                <motion.circle
                  cx="280"
                  cy="8"
                  r="3"
                  fill="#C7A257"
                  initial={{ opacity: 0, scale: 0 }}
                  animate={{ opacity: 1, scale: 1 }}
                  transition={{ delay: 2.5, duration: 0.4 }}
                >
                  <animate
                    attributeName="r"
                    values="3;5;3"
                    dur="2s"
                    repeatCount="indefinite"
                  />
                </motion.circle>
              )}
            </svg>
          </div>

          {/* Key Metrics - Enhanced glass grid */}
          <div className="grid grid-cols-3 gap-px bg-white/[0.04] border border-white/[0.06] overflow-hidden">
            {heroStats.map((stat, i) => (
              <motion.div
                key={i}
                className="bg-[#080808] p-3 sm:p-4 text-center relative group shadow-elevation-shift"
                whileHover={{ backgroundColor: "rgba(199,162,87,0.03)" }}
              >
                <stat.icon className="w-3 h-3 text-[#C7A257]/40 mx-auto mb-1.5 group-hover:text-[#C7A257]/70 transition-colors" />
                <motion.div
                  className={`text-base sm:text-lg font-mono mb-0.5 ${stat.color}`}
                  initial={{ opacity: 0, scale: 0.5 }}
                  animate={{ opacity: 1, scale: 1 }}
                  transition={{
                    delay: 1.8 + i * 0.2,
                    type: "spring",
                    stiffness: 200,
                  }}
                >
                  {stat.value}
                </motion.div>
                <div className="text-[8px] sm:text-[9px] font-body text-white/35 tracking-[0.2em] uppercase">
                  {stat.label}
                </div>
              </motion.div>
            ))}
          </div>
        </div>

        {/* Activity Feed */}
        <div className="border-t border-white/[0.06] px-4 py-3 space-y-1.5 max-h-[140px] overflow-hidden">
          <div className="text-[9px] font-mono text-white/25 tracking-[0.3em] uppercase mb-2 flex items-center gap-1.5">
            <Activity className="w-3 h-3" />
            Live Activity
          </div>
          {activityFeed.slice(0, 4).map((item, i) => (
            <motion.div
              key={i}
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 2 + i * 0.15, duration: 0.4 }}
              className="flex items-center justify-between text-[10px] sm:text-[11px] font-mono bg-white/[0.015] p-2 border border-white/[0.04] hover:border-[#C7A257]/20 transition-colors"
            >
              <div className="flex items-center gap-2">
                <span
                  className={`${item.action === "Payout"
                      ? "text-[#C7A257]"
                      : item.action === "Funded"
                        ? "text-white"
                        : "text-white/50"
                    }`}
                >
                  {item.action}
                </span>
                <span className="text-white/15">·</span>
                <span className="text-white/60">{item.amount}</span>
              </div>
              <span className="text-white/25">{item.time}</span>
            </motion.div>
          ))}
        </div>
      </div>
    </motion.div>
  );
}

/* ─── Hero Background (Enhanced with Spawn Engine layers) ─── */
function HeroBackground() {
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    const handleMouseMove = (e: MouseEvent) => {
      mouseX.set(e.clientX);
      mouseY.set(e.clientY);
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, [mouseX, mouseY]);

  const backgroundGlow = useMotionTemplate`radial-gradient(1400px circle at ${mouseX}px ${mouseY}px, rgba(199,162,87,0.04), transparent 50%)`;

  if (!mounted) return null;

  return (
    <div className="absolute inset-0 z-0 overflow-hidden pointer-events-none">
      {/* Magnetic Cursor Warp — Chaos Modifier */}
      <motion.div
        className="absolute inset-0"
        style={{ background: backgroundGlow }}
      />

      {/* Lamp Beam Effect */}
      <div className="lamp-beam" />

      {/* Dot-matrix underlay — Chaos Modifier */}
      <div
        className="absolute inset-0 opacity-20"
        style={{
          backgroundImage: `radial-gradient(circle at center, rgba(199,162,87,0.15) 1px, transparent 1px)`,
          backgroundSize: "28px 28px",
          maskImage: "linear-gradient(to bottom, black 10%, transparent 80%)",
          WebkitMaskImage: "linear-gradient(to bottom, black 10%, transparent 80%)",
        }}
      />

      {/* Scan-line overlay — Chaos Modifier */}
      <div
        className="absolute inset-0 pointer-events-none opacity-[0.02]"
        style={{
          backgroundImage: `linear-gradient(to bottom, transparent 50%, rgba(255,255,255,0.5) 50%)`,
          backgroundSize: "100% 4px",
        }}
      />

      {/* Ambient Orbs */}
      <motion.div
        className="absolute w-[1000px] h-[1000px] -top-[500px] right-[-300px] rounded-full blur-[120px]"
        style={{
          background: "radial-gradient(circle, rgba(199,162,87,0.12) 0%, transparent 70%)",
        }}
        animate={{
          scale: [1, 1.15, 1],
          opacity: [0.4, 0.7, 0.4],
        }}
        transition={{ duration: 12, repeat: Infinity, ease: "easeInOut" }}
      />
      <motion.div
        className="absolute w-[600px] h-[600px] top-[50%] -left-[250px] rounded-full blur-[140px]"
        style={{
          background: "radial-gradient(circle, rgba(199,162,87,0.06) 0%, transparent 70%)",
        }}
        animate={{
          scale: [1, 1.4, 1],
        }}
        transition={{ duration: 18, repeat: Infinity, ease: "easeInOut", delay: 3 }}
      />

      {/* Floating Particles */}
      <FloatingParticles />

      {/* Noise grain — Chaos Modifier */}
      <div className="absolute inset-0 noise-overlay opacity-[0.12]" />
    </div>
  );
}

/* ─── TRUST BADGES ROW ─── */
function HeroTrustRow() {
